const getBrowser = global.get('getBrowser');
if (!getBrowser) {
    msg.payload = { success: false, error: 'Browser service not available. Puppeteer may still be installing.' };
    msg.statusCode = 503;
    return msg;
}

const url = msg.payload.url;
const html = msg.payload.html;

if (!url && !html) {
    msg.payload = { success: false, error: 'Provide either \"url\" or \"html\" in the request body.' };
    msg.statusCode = 400;
    return msg;
}

try {
    const browser = await getBrowser();
    const page = await browser.newPage();
    try {
        await page.setViewport({ width: 1280, height: 800 });
        if (url) {
            await page.goto(url, { waitUntil: 'networkidle2', timeout: 60000 });
        } else {
            await page.setContent(html, { waitUntil: 'networkidle2', timeout: 60000 });
        }
        // Wait for Sandpack preview iframe to render if present
        try {
            const iframeHandle = await page.waitForSelector('.sp-preview-iframe', { timeout: 30000 });
            // Wait for Sandpack to finish compiling inside the iframe
            await new Promise(r => setTimeout(r, 3000));
        } catch (e) {
            // No Sandpack iframe found — proceed with screenshot as normal
        }
        const screenshot = await page.screenshot({ encoding: 'base64', fullPage: false });
        msg.payload = { success: true, image: 'data:image/png;base64,' + screenshot };
    } finally {
        await page.close();
    }
} catch (err) {
    msg.payload = { success: false, error: err.message };
    msg.statusCode = 500;
}
return msg;

