const getBrowser = global.get('getBrowser');
if (!getBrowser) {
    msg.payload = { success: false, error: 'Browser service not available. Puppeteer may still be installing.' };
    msg.statusCode = 503;
    return msg;
}

const html = msg.payload.html;
if (!html) {
    msg.payload = { success: false, error: 'Provide "html" in the request body.' };
    msg.statusCode = 400;
    return msg;
}

try {
    const browser = await getBrowser();
    const page = await browser.newPage();
    try {
        await page.setContent(html, { waitUntil: 'networkidle0', timeout: 30000 });
        const pdf = await page.pdf({ format: 'A4', printBackground: true });
        const base64 = pdf.toString('base64');
        msg.payload = { success: true, pdf: 'data:application/pdf;base64,' + base64 };
    } finally {
        await page.close();
    }
} catch (err) {
    msg.payload = { success: false, error: err.message };
    msg.statusCode = 500;
}
return msg;

const targetUrl = msg.req.query.url;

if (!targetUrl) {
    msg.payload = "Missing URL parameter";
    msg.statusCode = 400;
    return msg;
}

let parsed;
try {
    parsed = new URL(targetUrl);
} catch (e) {
    msg.payload = "Invalid URL";
    msg.statusCode = 400;
    return msg;
}

const client = parsed.protocol === "https:" ? https : http;

return new Promise((resolve) => {
    const options = {
        hostname: parsed.hostname,
        port: parsed.port || (parsed.protocol === "https:" ? 443 : 80),
        path: parsed.pathname + parsed.search,
        method: "GET",
        headers: {
            "User-Agent": msg.req.headers["user-agent"] || "AgentOS-Proxy"
        }
    };

    const proxyReq = client.request(options, (response) => {
        const chunks = [];

        msg.headers = Object.assign({}, response.headers);
        delete msg.headers["x-frame-options"];
        delete msg.headers["content-security-policy"];

        msg.statusCode = response.statusCode;

        response.on("data", (chunk) => {
            chunks.push(chunk);
        });

        response.on("end", () => {
            const raw = Buffer.concat(chunks);
            const contentType = (response.headers["content-type"] || "").toLowerCase();
            if (contentType.includes("text/html")) {
                let html = raw.toString("utf8");
                const baseTag = '<base href="' + parsed.origin + '/">';
                if (/<head[^>]*>/i.test(html)) {
                    html = html.replace(/<head([^>]*)>/i, '<head$1>' + baseTag);
                } else {
                    html = baseTag + html;
                }
                msg.payload = html;
            } else {
                msg.payload = raw;
            }
            resolve(msg);
        });
    });

    proxyReq.on("error", (err) => {
        msg.payload = "Proxy error: " + err.message;
        msg.statusCode = 500;
        resolve(msg);
    });

    proxyReq.end();
});

const action = msg.payload.action;
if (!action) {
    msg.payload = { success: false, error: "Missing action field. Use: goto, click, type, screenshot" };
    msg.statusCode = 400;
    return msg;
}

try {
    let browser = global.get("activeBrowser");
    let page = global.get("activePage");

    if (!browser || !browser.isConnected()) {
        const userDataDir = path.join(os.homedir(), ".node-red-standalone", "chrome-profile-data");
        browser = await puppeteer.launch({
            headless: true,
            userDataDir: userDataDir,
            args: ["--no-sandbox", "--disable-setuid-sandbox"]
        });
        page = await browser.newPage();
        await page.setViewport({ width: 1280, height: 800 });
        global.set("activeBrowser", browser);
        global.set("activePage", page);
    }

    if (!page || page.isClosed()) {
        page = await browser.newPage();
        await page.setViewport({ width: 1280, height: 800 });
        global.set("activePage", page);
    }

    if (action === "goto") {
        if (!msg.payload.url) {
            msg.payload = { success: false, error: "Missing url for goto action" };
            msg.statusCode = 400;
            return msg;
        }
        await page.goto(msg.payload.url, { waitUntil: "networkidle2" });
    } else if (action === "click") {
        if (!msg.payload.selector) {
            msg.payload = { success: false, error: "Missing selector for click action" };
            msg.statusCode = 400;
            return msg;
        }
        await page.click(msg.payload.selector);
    } else if (action === "type") {
        if (!msg.payload.selector || !msg.payload.text) {
            msg.payload = { success: false, error: "Missing selector or text for type action" };
            msg.statusCode = 400;
            return msg;
        }
        await page.type(msg.payload.selector, msg.payload.text);
    } else if (action === "screenshot") {
        // Just take the screenshot below
    } else {
        msg.payload = { success: false, error: "Unknown action: " + action + ". Use: goto, click, type, screenshot" };
        msg.statusCode = 400;
        return msg;
    }

    const screenshot = await page.screenshot({ encoding: "base64" });
    const dom = await page.evaluate(() => document.body.innerText.substring(0, 5000));

    msg.payload = { success: true, screenshot: screenshot, dom: dom };
    return msg;
} catch (err) {
    msg.payload = { success: false, error: err.message };
    msg.statusCode = 500;
    return msg;
}
